{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and a simple alcohol (ethanol) in the presence of dry hydrogen chloride. This is the quintessential first step of the Pinner reaction, as described in textbooks. The reactants and product are small, acyclic, and lack complex functional groups, making it a clear and unambiguous example of the core transformation.",
    "collision_avoidance_note": "The use of simple, acyclic aliphatic substrates (acetonitrile, ethanol) avoids overlap with reactions involving aromatic rings (e.g., Friedel-Crafts, Gattermann), complex rearrangements, or other named reactions that might involve nitriles in a different context. The product is the specific Pinner salt intermediate, which is characteristic of this reaction, rather than downstream hydrolysis products like esters, which could be formed by many other routes (e.g., Fischer esterification)."
  }
}
